class SecureCredentialService {
  // flutter_secure_storage uses Keychain on iOS and EncryptedSharedPreferences on Android
  final FlutterSecureStorage _secureStorage = const FlutterSecureStorage(
    aOptions: AndroidOptions(encryptedSharedPreferences: true),
    iOptions: IOSOptions(accessibility: KeychainAccessibility.first_unlock_this_device),
  );

  static const String _awsAccessKeyId = 'aws_access_key_id';
  static const String _awsSecretAccessKey = 'aws_secret_access_key';
  static const String _googleCloudApiKey = 'google_cloud_vision_api_key';
  static const String _awsS3Bucket = 'aws_s3_bucket';
  static const String _awsRegion = 'aws_region';

  /// Initialize credentials from environment variables (loaded from .env)
  /// This should be called once during app startup.
  Future<void> initializeFromEnv() async {
    // Load from .env file (which is in .gitignore)
    final awsAccessKey = dotenv.env['AWS_ACCESS_KEY_ID'];
    final awsSecretKey = dotenv.env['AWS_SECRET_ACCESS_KEY'];
    final googleApiKey = dotenv.env['GOOGLE_CLOUD_VISION_API_KEY'];
    final s3Bucket = dotenv.env['AWS_S3_BUCKET'];
    final awsRegion = dotenv.env['AWS_REGION'];

    if (awsAccessKey == null || awsSecretKey == null || googleApiKey == null) {
      throw CredentialException(
        'Missing required environment variables. '
        'Ensure .env file exists with AWS_ACCESS_KEY_ID, '
        'AWS_SECRET_ACCESS_KEY, and GOOGLE_CLOUD_VISION_API_KEY.',
      );
    }

    // Store in secure storage (encrypted at rest)
    await _secureStorage.write(key: _awsAccessKeyId, value: awsAccessKey);
    await _secureStorage.write(key: _awsSecretAccessKey, value: awsSecretKey);
    await _secureStorage.write(key: _googleCloudApiKey, value: googleApiKey);
    if (s3Bucket != null) {
      await _secureStorage.write(key: _awsS3Bucket, value: s3Bucket);
    }
    if (awsRegion != null) {
      await _secureStorage.write(key: _awsRegion, value: awsRegion);
    }
  }

  Future<String> getAwsAccessKeyId() async {
    final value = await _secureStorage.read(key: _awsAccessKeyId);
    if (value == null) throw CredentialException('AWS Access Key ID not found in secure storage');
    return value;
  }

  Future<String> getAwsSecretAccessKey() async {
    final value = await _secureStorage.read(key: _awsSecretAccessKey);
    if (value == null) throw CredentialException('AWS Secret Access Key not found in secure storage');
    return value;
  }

  Future<String> getGoogleCloudApiKey() async {
    final value = await _secureStorage.read(key: _googleCloudApiKey);
    if (value == null) throw CredentialException('Google Cloud API Key not found in secure storage');
    return value;
  }

  Future<String> getAwsS3Bucket() async {
    final value = await _secureStorage.read(key: _awsS3Bucket);
    return value ?? 'hackathon-photo-bucket';
  }

  Future<String> getAwsRegion() async {
    final value = await _secureStorage.read(key: _awsRegion);
    return value ?? 'us-east-1';
  }

  /// Clear all stored credentials (useful for logout/reset)
  Future<void> clearAll() async {
    await _secureStorage.deleteAll();
  }

  /// Check if credentials are already stored
  Future<bool> hasCredentials() async {
    final awsKey = await _secureStorage.read(key: _awsAccessKeyId);
    final awsSecret = await _secureStorage.read(key: _awsSecretAccessKey);
    final googleKey = await _secureStorage.read(key: _googleCloudApiKey);
    return awsKey != null && awsSecret != null && googleKey != null;
  }
}

class CredentialException implements Exception {
  final String message;
  CredentialException(this.message);

  @override
  String toString() => 'CredentialException: $message';
}

// ============================================================
// AWS S3 Upload Service (using AWS Signature V4)
// ============================================================
class S3UploadService {
  final SecureCredentialService _credentialService;

  S3UploadService(this._credentialService);

  Future<String> uploadPhoto(File imageFile) async {
    final accessKey = await _credentialService.getAwsAccessKeyId();
    final secretKey = await _credentialService.getAwsSecretAccessKey();
    final bucket = await _credentialService.getAwsS3Bucket();
    final region = await _credentialService.getAwsRegion();

    final fileName = 'photos/${DateTime.now().millisecondsSinceEpoch}_${imageFile.path.split('/').last}';
    final bytes = await imageFile.readAsBytes();
    final contentType = _getContentType(imageFile.path);

    final url = await _signAndUpload(
      accessKey: accessKey,
      secretKey: secretKey,
      bucket: bucket,
      region: region,
      objectKey: fileName,
      bytes: bytes,
      contentType: contentType,
    );

    return url;
  }

  String _getContentType(String path) {
    final ext = path.split('.').last.toLowerCase();
    switch (ext) {
      case 'jpg':
      case 'jpeg':
        return 'image/jpeg';
      case 'png':
        return 'image/png';
      case 'gif':
        return 'image/gif';
      case 'webp':
        return 'image/webp';
      default:
        return 'application/octet-stream';
    }
  }

  Future<String> _signAndUpload({
    required String accessKey,
    required String secretKey,
    required String bucket,
    required String region,
    required String objectKey,
    required Uint8List bytes,
    required String contentType,
  }) async {
    final host = '$bucket.s3.$region.amazonaws.com';
    final endpoint = 'https://$host/$objectKey';
    final now = DateTime.now().toUtc();
    final dateStamp = _formatDate(now);
    final amzDate = _formatAmzDate(now);

    final payloadHash = sha256.convert(bytes).toString();

    final headers = <String, String>{
      'Host': host,
      'Content-Type': contentType,
      'x-amz-content-sha256': payloadHash,
      'x-amz-date': amzDate,
    };

    final signedHeaderKeys = (headers.keys.toList()..sort()).map((k) => k.toLowerCase()).toList();
    final signedHeadersStr = signedHeaderKeys.join(';');

    final canonicalHeaders = signedHeaderKeys.map((k) => '$k:${headers[k == 'host' ? 'Host' : k == 'content-type' ? 'Content-Type' : k == 'x-amz-content-sha256' ? 'x-amz-content-sha256' : 'x-amz-date']}\n').join();

    final canonicalHeadersSorted = <String>[];
    final sortedKeys = headers.keys.toList()..sort((a, b) => a.toLowerCase().compareTo(b.toLowerCase()));
    for (final key in sortedKeys) {
      canonicalHeadersSorted.add('${key.toLowerCase()}:${headers[key]!.trim()}');
    }

    final canonicalRequest = [
      'PUT',
      '/${Uri.encodeComponent(objectKey).replaceAll('%2F', '/')}',
      '',
      '${canonicalHeadersSorted.join('\n')}\n',
      signedHeadersStr,
      payloadHash,
    ].join('\n');

    final credentialScope = '$dateStamp/$region/s3/aws4_request';
    final stringToSign = [
      'AWS4-HMAC-SHA256',
      amzDate,
      credentialScope,
      sha256.convert(utf8.encode(canonicalRequest)).toString(),
    ].join('\n');

    final signingKey = _getSignatureKey(secretKey, dateStamp, region, 's3');
    final signature = Hmac(sha256, signingKey).convert(utf8.encode(stringToSign)).toString();

    final authorization = 'AWS4-HMAC-SHA256 Credential=$accessKey/$credentialScope, SignedHeaders=$signedHeadersStr, Signature=$signature';

    final response = await http.put(
      Uri.parse(endpoint),
      headers: {
        ...headers,
        'Authorization': authorization,
      },
      body: bytes,
    );

    if (response.statusCode == 200 || response.statusCode == 201) {
      return endpoint;
    } else {
      throw S3UploadException(
        'S3 upload failed with status ${response.statusCode}: ${response.body}',
      );
    }
  }

  List<int> _getSignatureKey(String key, String dateStamp, String region, String service) {
    final kDate = Hmac(sha256, utf8.encode('AWS4$key')).convert(utf8.encode(dateStamp)).bytes;
    final kRegion = Hmac(sha256, kDate).convert(utf8.encode(region)).bytes;
    final kService = Hmac(sha256, kRegion).convert(utf8.encode(service)).bytes;
    final kSigning = Hmac(sha256, kService).convert(utf8.encode('aws4_request')).bytes;
    return kSigning;
  }

  String _formatDate(DateTime dt) =>
      '${dt.year}${dt.month.toString().padLeft(2, '0')}${dt.day.toString().padLeft(2, '0')}';

  String _formatAmzDate(DateTime dt) =>
      '${_formatDate(dt)}T${dt.hour.toString().padLeft(2, '0')}${dt.minute.toString().padLeft(2, '0')}${dt.second.toString().padLeft(2, '0')}Z';
}

class S3UploadException implements Exception {
  final String message;
  S3UploadException(this.message);

  @override
  String toString() => 'S3UploadException: $message';
}

// ============================================================
// Google Cloud Vision Service
// ============================================================
class VisionAnalysisService {
  final SecureCredentialService _credentialService;

  VisionAnalysisService(this._credentialService);

  Future<ImageAnalysisResult> analyzeImage(Uint8List imageBytes) async {
    final apiKey = await _credentialService.getGoogleCloudApiKey();

    final base64Image = base64Encode(imageBytes);

    final requestBody = jsonEncode({
      'requests': [
        {
          'image': {'content': base64Image},
          'features': [
            {'type': 'LABEL_DETECTION', 'maxResults': 10},
            {'type': 'FACE_DETECTION', 'maxResults': 5},
            {'type': 'TEXT_DETECTION', 'maxResults': 5},
            {'type': 'SAFE_SEARCH_DETECTION'},
            {'type': 'IMAGE_PROPERTIES'},
          ],
        },
      ],
    });

    final response = await http.post(
      Uri.parse('https://vision.googleapis.com/v1/images:annotate?key=$apiKey'),
      headers: {'Content-Type': 'application/json'},
      body: requestBody,
    );

    if (response.statusCode == 200) {
      final data = jsonDecode(response.body);
      return ImageAnalysisResult.fromJson(data['responses'][0]);
    } else {
      throw VisionApiException(
        'Vision API failed with status ${response.statusCode}: ${response.body}',
      );
    }
  }
}

class ImageAnalysisResult {
  final List<LabelAnnotation> labels;
  final List<FaceAnnotation> faces;
  final String? detectedText;
  final SafeSearchResult? safeSearch;
  final List<DominantColor> dominantColors;

  ImageAnalysisResult({
    required this.labels,
    required this.faces,
    this.detectedText,
    this.safeSearch,
    required this.dominantColors,
  });

  factory ImageAnalysisResult.fromJson(Map<String, dynamic> json) {
    final labels = (json['labelAnnotations'] as List<dynamic>?)
            ?.map((l) => LabelAnnotation(
                  description: l['description'] as String,
                  score: (l['score'] as num).toDouble(),
                ))
            .toList() ??
        [];

    final faces = (json['faceAnnotations'] as List<dynamic>?)
            ?.map((f) => FaceAnnotation(
                  joyLikelihood: f['joyLikelihood'] as String? ?? 'UNKNOWN',
                  sorrowLikelihood: f['sorrowLikelihood'] as String? ?? 'UNKNOWN',
                  angerLikelihood: f['angerLikelihood'] as String? ?? 'UNKNOWN',
                  surpriseLikelihood: f['surpriseLikelihood'] as String? ?? 'UNKNOWN',
                  detectionConfidence: (f['detectionConfidence'] as num?)?.toDouble() ?? 0.0,
                ))
            .toList() ??
        [];

    String? detectedText;
    final textAnnotations = json['textAnnotations'] as List<dynamic>?;
    if (textAnnotations != null && textAnnotations.isNotEmpty) {
      detectedText = textAnnotations[0]['description'] as String?;
    }

    SafeSearchResult? safeSearch;
    final safeSearchJson = json['safeSearchAnnotation'] as Map<String, dynamic>?;
    if (safeSearchJson != null) {
      safeSearch = SafeSearchResult(
        adult: safeSearchJson['adult'] as String? ?? 'UNKNOWN',
        violence: safeSearchJson['violence'] as String? ?? 'UNKNOWN',
        racy: safeSearchJson['racy'] as String? ?? 'UNKNOWN',
      );
    }

    final dominantColors = <DominantColor>[];
    final imageProperties = json['imagePropertiesAnnotation'] as Map<String, dynamic>?;
    if (imageProperties != null) {
      final colors = imageProperties['dominantColors']?['colors'] as List<dynamic>?;
      if (colors != null) {
        for (final c in colors.take(5)) {
          final colorInfo = c['color'] as Map<String, dynamic>?;
          if (colorInfo != null) {
            dominantColors.add(DominantColor(
              red: (colorInfo['red'] as num?)?.toInt() ?? 0,
              green: (colorInfo['green'] as num?)?.toInt() ?? 0,
              blue: (colorInfo['blue'] as num?)?.toInt() ?? 0,
              score: (c['score'] as num?)?.toDouble() ?? 0.0,
              pixelFraction: (c['pixelFraction'] as num?)?.toDouble() ?? 0.0,
            ));
          }
        }
      }
    }

    return ImageAnalysisResult(
      labels: labels,
      faces: faces,
      detectedText: detectedText,
      safeSearch: safeSearch,
      dominantColors: dominantColors,
    );
  }
}

class LabelAnnotation {
  final String description;
  final double score;

  LabelAnnotation({required this.description, required this.score});
}

class FaceAnnotation {
  final String joyLikelihood;
  final String sorrowLikelihood;
  final String angerLikelihood;
  final String surpriseLikelihood;
  final double detectionConfidence;

  FaceAnnotation({
    required this.joyLikelihood,
    required this.sorrowLikelihood,
    required this.angerLikelihood,
    required this.surpriseLikelihood,
    required this.detectionConfidence,
  });
}

class SafeSearchResult {
  final String adult;
  final String violence;
  final String racy;

  SafeSearchResult({required this.adult, required this.violence, required this.racy});
}

class DominantColor {
  final int red;
  final int green;
  final int blue;
  final double score;
  final double pixelFraction;

  DominantColor({
    required this.red,
    required this.green,
    required this.blue,
    required this.score,
    required this.pixelFraction,
  });

  Color toColor() => Color.fromRGBO(red, green, blue, 1.0);
}

