}

// ============================================================
// App State Management
// ============================================================
class AppState extends ChangeNotifier {
  final SecureCredentialService _credentialService;
  late final S3UploadService _s3Service;
  late final VisionAnalysisService _visionService;

  bool _isInitialized = false;
  bool _isLoading = false;
  String? _error;
  File? _selectedImage;
  String? _uploadedUrl;
  ImageAnalysisResult? _analysisResult;

  bool get isInitialized => _isInitialized;
  bool get isLoading => _isLoading;
  String? get error => _error;
  File? get selectedImage => _selectedImage;
  String? get uploadedUrl => _uploadedUrl;
  ImageAnalysisResult? get analysisResult => _analysisResult;

  AppState(this._credentialService) {
    _s3Service = S3UploadService(_credentialService);
    _visionService = VisionAnalysisService(_credentialService);
  }

  Future<void> initialize() async {
    try {
      _isLoading = true;
      _error = null;
      notifyListeners();

      final hasCredentials = await _credentialService.hasCredentials();
      if (!hasCredentials) {
        await _credentialService.initializeFromEnv();
      }

      _isInitialized = true;
    } catch (e) {
      _error = 'Failed to initialize: ${e.toString()}';
    } finally {
      _isLoading = false;
      notifyListeners();
    }
  }

  Future<void> pickAndProcessImage(ImageSource source) async {
    try {
      _isLoading = true;
      _error = null;
      _analysisResult = null;
      _uploadedUrl = null;
      notifyListeners();

      final picker = ImagePicker();
      final pickedFile = await picker.pickImage(
        source: source,
        maxWidth: 1920,
        maxHeight: 1080,
        imageQuality: 85,
      );

      if (pickedFile == null) {
        _isLoading = false;
        notifyListeners();
        return;
      }

      _selectedImage = File(pickedFile.path);
      notifyListeners();

      // Upload to S3 and analyze in parallel
      final imageBytes = await _selectedImage!.readAsBytes();

      final results = await Future.wait([
        _s3Service.uploadPhoto(_selectedImage!),
        _visionService.analyzeImage(imageBytes),
      ]);

      _uploadedUrl = results[0] as String;
      _analysisResult = results[1] as ImageAnalysisResult;
    } catch (e) {
      _error = e.toString();
    } finally {
      _isLoading = false;
      notifyListeners();
    }
  }

  void clearResults() {
    _selectedImage = null;
    _uploadedUrl = null;
    _analysisResult = null;
    _error = null;
    notifyListeners();
  }
}

