// Main App
// ============================================================
Future<void> main() async {
  WidgetsFlutterBinding.ensureInitialized();

  // Load .env file (this file must be in .gitignore)
  await dotenv.load(fileName: '.env');

  final credentialService = SecureCredentialService();

  runApp(
    ChangeNotifierProvider(
      create: (_) => AppState(credentialService)..initialize(),
      child: const PhotoAnalysisApp(),
    ),
  );
}

