            Card(
              child: Padding(
                padding: const EdgeInsets.all(12),
                child: Column(
                  crossAxisAlignment: CrossAxisAlignment.start,
                  children: [
                    Row(
                      children: [
                        Icon(Icons.cloud_done, color: Colors.green[700]),
                        const SizedBox(width: 8),
                        const Text(
                          'Uploaded to S3',
                          style: TextStyle(fontWeight: FontWeight.bold, fontSize: 16),
                        ),
                      ],
                    ),
                    const SizedBox(height: 8),
                    Text(
                      appState.uploadedUrl!,
                      style: const TextStyle(fontSize: 11, fontFamily: 'monospace'),
                    ),
                  ],
                ),
              ),
            ),
            const SizedBox(height: 12),
          ],

          // Analysis results
          if (appState.analysisResult != null) ...[
            _buildLabelsCard(context, appState.analysisResult!),
            const SizedBox(height: 12),
            if (appState.analysisResult!.faces.isNotEmpty)
              _buildFacesCard(context, appState.analysisResult!),
            if (appState.analysisResult!.faces.isNotEmpty) const SizedBox(height: 12),
            if (appState.analysisResult!.detectedText != null)
              _buildTextCard(context, appState.analysisResult!),
            if (appState.analysisResult!.detectedText != null) const SizedBox(height: 12),
            if (appState.analysisResult!.dominantColors.isNotEmpty)
              _buildColorsCard(context, appState.analysisResult!),
            if (appState.analysisResult!.dominantColors.isNotEmpty) const SizedBox(height: 12),
            if (appState.analysisResult!.safeSearch != null)
              _buildSafeSearchCard(context, appState.analysisResult!),
          ],

          const SizedBox(height: 80),
        ],
      ),
    );
  }

  Widget _buildLabelsCard(BuildContext context, ImageAnalysisResult result) {
    return Card(
      child: Padding(
        padding: const EdgeInsets.all(12),
        child: Column(
          crossAxisAlignment: CrossAxisAlignment.start,
          children: [
            const Row(
              children: [
                Icon(Icons.label, color: Colors.indigo),
                SizedBox(width: 8),
                Text('Labels', style: TextStyle(fontWeight: FontWeight.bold, fontSize: 16)),
              ],
            ),
            const SizedBox(height: 8),
            Wrap(
              spacing: 6,
              runSpacing: 6,
              children: result.labels.map((label) {
                return Chip(
                  label: Text('${label.description} (${(label.score * 100).toStringAsFixed(0)}%)'),
                  backgroundColor: Colors.indigo.withOpacity(0.1),
                );
              }).toList(),
            ),
          ],
        ),
      ),
    );
  }

  Widget _buildFacesCard(BuildContext context, ImageAnalysisResult result) {
    return Card(
      child: Padding(
        padding: const EdgeInsets.all(12),
        child: Column(
          crossAxisAlignment: CrossAxisAlignment.start,
          children: [
            Row(
              children: [
                const Icon(Icons.face, color: Colors.orange),
                const SizedBox(width: 8),
                Text(
                  'Faces Detected: ${result.faces.length}',
                  style: const TextStyle(fontWeight: FontWeight.bold, fontSize: 16),
                ),
              ],
            ),
            const SizedBox(height: 8),
            ...result.faces.asMap().entries.map((entry) {
              final i = entry.key;
              final face = entry.value;
              return Padding(
                padding: const EdgeInsets.only(bottom: 8),
                child: Column(
                  crossAxisAlignment: CrossAxisAlignment.start,
                  children: [
                    Text('Face ${i + 1} (${(face.detectionConfidence * 100).toStringAsFixed(0)}% confidence)'),
                    Text('  😊 Joy: ${face.joyLikelihood}'),
                    Text('  😢 Sorrow: ${face.sorrowLikelihood}'),
                    Text('  😠 Anger: ${face.angerLikelihood}'),
                    Text('  😲 Surprise: ${face.surpriseLikelihood}'),
                  ],
                ),
              );
            }),
          ],
        ),
      ),
    );
  }

  Widget _buildTextCard(BuildContext context, ImageAnalysisResult result) {
    return Card(
      child: Padding(
        padding: const EdgeInsets.all(12),
        child: Column(
          crossAxisAlignment: CrossAxisAlignment.start,
          children: [
            const Row(
              children: [
                Icon(Icons.text_fields, color: Colors.teal),
                SizedBox(width: 8),
                Text('Detected Text', style: TextStyle(fontWeight: FontWeight.bold, fontSize: 16)),
              ],
            ),
            const SizedBox(height: 8),
            Container(
              padding: const EdgeInsets.all(8),
              decoration: BoxDecoration(
                color: Colors.grey.withOpacity(0.1),
                borderRadius: BorderRadius.circular(8),
              ),
              child: Text(
                result.detectedText ?? '',
                style: const TextStyle(fontFamily: 'monospace'),
              ),
            ),
          ],
        ),
      ),
    );
  }

  Widget _buildColorsCard(BuildContext context, ImageAnalysisResult result) {
    return Card(
      child: Padding(
        padding: const EdgeInsets.all(12),
        child: Column(
          crossAxisAlignment: CrossAxisAlignment.start,
          children: [
            const Row(
              children: [
                Icon(Icons.palette, color: Colors.purple),
                SizedBox(width: 8),
                Text('Dominant Colors', style: TextStyle(fontWeight: FontWeight.bold, fontSize: 16)),
              ],
            ),
            const SizedBox(height: 8),
            Row(
              children: result.dominantColors.map((color) {
                return Expanded(
                  child: Column(
                    children: [
                      Container(
                        height: 40,
                        decoration: BoxDecoration(
                          color: color.toColor(),
                          borderRadius: BorderRadius.circular(6),
                        ),
                      ),
                      const SizedBox(height: 4),
                      Text(
                        '${(color.pixelFraction * 100).toStringAsFixed(0)}%',
                        style: const TextStyle(fontSize: 10),
                      ),
                    ],
                  ),
                );
              }).toList(),
            ),
          ],
        ),
      ),
    );
  }

  Widget _buildSafeSearchCard(BuildContext context, ImageAnalysisResult result) {
    final ss = result.safeSearch!;
    return Card(
      child: Padding(
        padding: const EdgeInsets.all(12),
        child: Column(
          crossAxisAlignment: CrossAxisAlignment.start,
          children: [
            const Row(
              children: [
                Icon(Icons.shield, color: Colors.green),
                SizedBox(width: 8),
                Text('Safe Search', style: TextStyle(fontWeight: FontWeight.bold, fontSize: 16)),
              ],
            ),
            const SizedBox(height: 8),
            Text('Adult: ${ss.adult}'),
            Text('Violence: ${ss.violence}'),
            Text('Racy: ${ss.racy}'),
          ],
        ),
      ),
    );
  }
}

